'use strict';

// Human-architect review queue — closes the §14 "correlated-LLM-
// reviewer failure" gap from the 2026-05-12 brainstorm.
//
// Codex's framing: security architecture generated by Claude +
// reviewed by Grok + reviewed by Codex still shares LLM training
// data exposure. A human security architect breaks that correlation.
//
// This module is the BOOKKEEPING that makes that human review
// non-skippable for high-stakes decisions:
//
//   • Items get queued automatically when they touch a "high-stakes"
//     surface (live-write authority, kernel invariant change,
//     promotion gate change, anchor key change, etc.)
//   • Each item has an SLA (default 7 days) and an escalation date
//   • Human reviewer signs the item with name + timestamp + decision
//   • No LLM signature can satisfy a human-architect requirement
//   • Hash-chained ledger so signatures can't be forged
//
// API:
//   queueItem({title, surfaces, riskLevel, evidence, slaDays?})
//     → {itemId, entry}
//   listItems({status?, overdue?, limit?})
//   signItem(itemId, {humanName, decision, rationale})
//     → records human review; THROWS if humanName looks like an
//       LLM identifier (claude-, gpt-, grok-, llama-, etc.)
//   verifyQueueLedger() → hash chain integrity
//
// Status: 'queued' | 'signed-approve' | 'signed-reject' | 'overdue'

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const LLM_NAME_PATTERNS = [
  /^claude/i, /^gpt/i, /^chatgpt/i, /^grok/i, /^gemini/i, /^llama/i,
  /^mistral/i, /^codex/i, /^anthropic/i, /^openai/i, /^xai/i,
  /^google[-_ ]ai/i, /^deepseek/i, /^qwen/i, /^o1$/i, /^o3$/i,
  /^assistant$/i, /^bot$/i, /^ai$/i,
];

function looksLikeLlmName(name) {
  if (!name || typeof name !== 'string') return false;
  return LLM_NAME_PATTERNS.some((p) => p.test(name.trim()));
}

function ledgerPath(opts = {}) {
  return opts.ledgerPath || path.join(opts.dataDir || '', 'security', 'architect-review-ledger.jsonl');
}

function ensureFile(filePath) {
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  if (!fs.existsSync(filePath)) fs.writeFileSync(filePath, '', 'utf8');
}

function readLedger(filePath) {
  if (!fs.existsSync(filePath)) return [];
  const raw = fs.readFileSync(filePath, 'utf8').trim();
  if (!raw) return [];
  return raw.split('\n').filter(Boolean).map((l) => {
    try { return JSON.parse(l); } catch (_) { return null; }
  }).filter(Boolean);
}

function entryHash(entry) {
  return 'sha256:' + crypto.createHash('sha256').update(JSON.stringify({
    sequence: entry.sequence,
    previousHash: entry.previousHash,
    eventKind: entry.eventKind,
    itemId: entry.itemId,
    title: entry.title,
    surfaces: entry.surfaces,
    riskLevel: entry.riskLevel,
    evidence: entry.evidence,
    slaDays: entry.slaDays,
    queuedAt: entry.queuedAt,
    dueAt: entry.dueAt,
    statusAfter: entry.statusAfter,
    humanName: entry.humanName,
    decision: entry.decision,
    rationale: entry.rationale,
    signedAt: entry.signedAt,
  })).digest('hex');
}

function _appendEvent(filePath, event) {
  ensureFile(filePath);
  const existing = readLedger(filePath);
  const previous = existing[existing.length - 1] || null;
  const enriched = { sequence: existing.length + 1, previousHash: previous ? previous.entryHash : null, ...event };
  enriched.entryHash = entryHash(enriched);
  fs.appendFileSync(filePath, JSON.stringify(enriched) + '\n', 'utf8');
  return enriched;
}

function queueItem({ title, surfaces, riskLevel, evidence, slaDays = 7 }, opts = {}) {
  if (!title) throw new Error('title is required');
  if (!Array.isArray(surfaces) || surfaces.length === 0) throw new Error('surfaces (array) is required');
  if (!riskLevel) throw new Error('riskLevel is required');
  const filePath = ledgerPath(opts);
  const queuedAt = opts.queuedAt || new Date().toISOString();
  const dueAt = new Date(Date.parse(queuedAt) + slaDays * 24 * 60 * 60 * 1000).toISOString();
  const itemId = 'arch-review-' + crypto.createHash('sha256').update(title + '|' + queuedAt).digest('hex').slice(0, 16);

  return _appendEvent(filePath, {
    eventKind: 'queued',
    itemId,
    title,
    surfaces,
    riskLevel,
    evidence: evidence || [],
    slaDays,
    queuedAt,
    dueAt,
    statusAfter: 'queued',
    humanName: null,
    decision: null,
    rationale: null,
    signedAt: null,
  });
}

function _eventsByItem(opts) {
  const all = readLedger(ledgerPath(opts));
  const map = new Map();
  for (const e of all) {
    if (!map.has(e.itemId)) map.set(e.itemId, []);
    map.get(e.itemId).push(e);
  }
  return map;
}

function _currentItem(itemId, opts) {
  const events = (readLedger(ledgerPath(opts)) || []).filter((e) => e.itemId === itemId);
  if (events.length === 0) return null;
  const first = events[0];
  const latest = events[events.length - 1];
  let status = latest.statusAfter;
  if (status === 'queued' && Date.now() > Date.parse(first.dueAt)) status = 'overdue';
  return {
    itemId,
    title: first.title,
    surfaces: first.surfaces,
    riskLevel: first.riskLevel,
    evidence: first.evidence,
    slaDays: first.slaDays,
    queuedAt: first.queuedAt,
    dueAt: first.dueAt,
    status,
    humanName: latest.humanName,
    decision: latest.decision,
    rationale: latest.rationale,
    signedAt: latest.signedAt,
    eventCount: events.length,
  };
}

function listItems(opts = {}) {
  const byItem = _eventsByItem(opts);
  const items = [];
  for (const itemId of byItem.keys()) {
    const item = _currentItem(itemId, opts);
    if (!item) continue;
    if (opts.status && item.status !== opts.status) continue;
    if (opts.overdue && item.status !== 'overdue') continue;
    items.push(item);
  }
  items.sort((a, b) => (a.dueAt || '').localeCompare(b.dueAt || ''));
  if (opts.limit) return items.slice(0, Number(opts.limit));
  return items;
}

function getItem(itemId, opts = {}) {
  return _currentItem(itemId, opts);
}

function signItem(itemId, { humanName, decision, rationale }, opts = {}) {
  if (!humanName) throw new Error('humanName is required');
  if (looksLikeLlmName(humanName)) {
    throw new Error(`humanName "${humanName}" looks like an LLM identifier — this queue requires non-LLM human review (correlated-failure mitigation, §14)`);
  }
  if (!decision) throw new Error('decision is required (approve | reject)');
  if (!['approve', 'reject'].includes(decision)) throw new Error('decision must be "approve" or "reject"');
  if (!rationale) throw new Error('rationale is required');

  const current = _currentItem(itemId, opts);
  if (!current) throw new Error('item not found: ' + itemId);
  if (current.status === 'signed-approve' || current.status === 'signed-reject') {
    throw new Error('item already signed');
  }

  const filePath = ledgerPath(opts);
  return _appendEvent(filePath, {
    eventKind: 'signed',
    itemId,
    title: current.title,
    surfaces: current.surfaces,
    riskLevel: current.riskLevel,
    evidence: current.evidence,
    slaDays: current.slaDays,
    queuedAt: current.queuedAt,
    dueAt: current.dueAt,
    statusAfter: decision === 'approve' ? 'signed-approve' : 'signed-reject',
    humanName,
    decision,
    rationale,
    signedAt: new Date().toISOString(),
  });
}

function verifyQueueLedger(opts = {}) {
  const filePath = ledgerPath(opts);
  if (!fs.existsSync(filePath)) return { ok: true, entries: 0, message: 'no_ledger_yet' };
  const events = readLedger(filePath);
  let prev = null;
  for (let i = 0; i < events.length; i++) {
    const e = events[i];
    if (e.sequence !== i + 1) return { ok: false, failedAt: i + 1, reason: 'sequence_gap' };
    if (e.previousHash !== (prev ? prev.entryHash : null)) return { ok: false, failedAt: i + 1, reason: 'previous_hash_mismatch' };
    if (entryHash(e) !== e.entryHash) return { ok: false, failedAt: i + 1, reason: 'entry_hash_mismatch' };
    prev = e;
  }
  return { ok: true, entries: events.length, headHash: prev ? prev.entryHash : null };
}

module.exports = {
  queueItem,
  listItems,
  getItem,
  signItem,
  verifyQueueLedger,
  looksLikeLlmName,
};
